BCE_URL_LIST = 'http://36.103.203.10:39000/list/encode'
BCE_URL = 'http://36.103.203.10:39000/encode'
OPENSEARCH_URL = 'http://10.100.10.22:19200'
INDEX_NAME= 'health_test_vectors'



class NewBceEmbedding(Embeddings):

    def embed_documents(self, texts: List[str]) -> List[List[float]]:
        """Embed search docs."""

        models_body = {
            "input": texts
        }
        headers = {'Content-Type': 'application/json'}
        result = requests.post(url=BCE_URL_LIST, json=models_body, headers=headers).json()

        return result['data']

    def embed_query(self, text: str) -> List[float]:
        """Embed query text."""

        models_body = {
            "input": text
        }
        headers = {'Content-Type': 'application/json'}
        result = requests.post(url=BCE_URL, json=models_body, headers=headers).json()

        return result['data'][0]


def text_vector(name: str,text: str, ):
    text_splitter = CharacterTextSplitter(
        chunk_size=40000,  # 默认4000
        chunk_overlap=0,  # # 默认200
        length_function=len,
    )
    docs = text_splitter.create_documents([text])
    print(f'切分的文档:::{docs}')
    documents_vector_store = get_documents_vector_store()
    for doc in docs:
        metadata = {
            "file_name": name,
            "file_path": "",
            "paper_title": name
        }
        doc_with_metadata = Document(page_content=doc.page_content, metadata=metadata)
        id = hashlib.md5(text.encode("utf-8")).hexdigest()
        #uuid.uuid4()
        documents_vector_store.add_documents([doc_with_metadata], ids=[id])


def get_documents_vector_store():
    embeddings = NewBceEmbedding()

    return OpenSearchVectorSearch(opensearch_url=OPENSEARCH_URL,
            index_name = INDEX_NAME,
            embedding_function=embeddings,
            is_aoss=False)


